use strict;
use warnings;

my $target = 67; # Sabit hedef sayi (demo amacli)

print "Sayi tahmin oyunu basladi! (1-100 arasi)\n";
print "(Bu demo, onceden belirlenmis tahminlerle calisir)\n\n";

my @guesses = (50, 75, 62, 68, 65, 67);
my $found = 0;

foreach my $guess (@guesses) {
    print "Tahmin: $guess\n";

    if ($guess == $target) {
        print "Tebrikler! Dogru tahmin: $target\n";
        $found = 1;
        last;
    } elsif ($guess < $target) {
        print "Daha buyuk bir sayi dene.\n\n";
    } else {
        print "Daha kucuk bir sayi dene.\n\n";
    }
}

unless ($found) {
    print "\nTahmin edilemedi. Dogru sayi: $target\n";
}

print "\nToplam deneme sayisi: " . scalar(@guesses) . "\n";
